<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">PATIENT COMMUNICATION</span><h1>Contact and Feedback</h1></div></div><div class="status-tabs"><a class="<?=$type==='messages'?'active':''?>" href="<?=url('admin/feedback?type=messages')?>">Contact Messages</a><a class="<?=$type==='feedback'?'active':''?>" href="<?=url('admin/feedback?type=feedback')?>">Patient Feedback</a></div><div class="admin-panel"><div class="table-wrap"><table><thead><tr><?php if($type==='messages'):?><th>Sender</th><th>Subject</th><th>Message</th><?php else:?><th>Patient</th><th>Service</th><th>Rating</th><th>Comments</th><?php endif;?><th>Date</th><th>Status</th><th>Update</th></tr></thead><tbody><?php foreach($rows as$x):?><tr><?php if($type==='messages'):?><td><?=e($x['name'])?><small><?=e($x['phone'])?> <?=e($x['email'])?></small></td><td><?=e($x['subject'])?></td><td><?=e(mb_strimwidth($x['message'],0,120,'…'))?></td><?php else:?><td><?=e($x['is_anonymous']?'Anonymous':($x['name']?:'Patient'))?></td><td><?=e($x['service'])?></td><td><?=str_repeat('★',(int)$x['rating'])?></td><td><?=e(mb_strimwidth($x['comments'],0,120,'…'))?></td><?php endif;?><td><?=date('d M Y',strtotime($x['created_at']))?></td><td><?=e($x['status'])?></td><td><form class="inline-update" method="post" action="<?=url('admin/feedback-status')?>"><?=csrf_field()?><input type="hidden" name="type" value="<?=e($type)?>"><input type="hidden" name="id" value="<?=$x['id']?>"><select name="status"><?php foreach(($type==='messages'?['new','read','resolved']:['pending','published','archived'])as$s):?><option <?=$x['status']===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><button class="btn small">Save</button></form></td></tr><?php endforeach;?></tbody></table></div></div></div></section>
